import React, { useState, useEffect, useRef } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

// ==================== مكون تفاصيل المجموعة ====================
const GroupDetailsModal = ({ group, onUpdateOrderStatus, onClose }) => {
  const [localOrders, setLocalOrders] = useState([...group.orders]);
  
  // تحديث حالة طلبية فردية
  const handleUpdateOrder = (orderId, newStatus) => {
    setLocalOrders(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus, updated: true } : order
    ));
    onUpdateOrderStatus(orderId, newStatus);
  };
  
  // تحديث جميع الطلبات في المجموعة
  const handleUpdateAll = (newStatus) => {
    setLocalOrders(prev => prev.map(order => ({ ...order, status: newStatus, updated: true })));
    group.orders.forEach(order => onUpdateOrderStatus(order.id, newStatus));
  };
  
  const stats = {
    total: localOrders.length,
    completed: localOrders.filter(o => o.status === 'completed').length,
    cancelled: localOrders.filter(o => o.status === 'cancelled').length,
    pending: localOrders.filter(o => o.status === 'pending').length,
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content-group" onClick={(e) => e.stopPropagation()}>
        <button onClick={onClose} className="close-btn">✕</button>
        
        <div className="group-details-header">
          <div className="group-icon">📋</div>
          <h2 className="group-title">{group.name}</h2>
          <p className="group-subtitle">السعر للواحدة: {group.price} دج</p>
        </div>
        
        {/* إحصائيات سريعة */}
        <div className="stats-row">
          <div className="stat-card pending">
            <span className="stat-number">{stats.pending}</span>
            <span className="stat-label">في الانتظار</span>
          </div>
          <div className="stat-card completed">
            <span className="stat-number">{stats.completed}</span>
            <span className="stat-label">تم التوصيل</span>
          </div>
          <div className="stat-card cancelled">
            <span className="stat-number">{stats.cancelled}</span>
            <span className="stat-label">ملغية</span>
          </div>
        </div>
        
        {/* أزرار شاملة */}
        <div className="group-actions-all">
          <button 
            onClick={() => handleUpdateAll('completed')}
            className="btn-livre-all"
            disabled={stats.pending === 0}
          >
            ✅ Livrer Tout ({stats.pending})
          </button>
          <button 
            onClick={() => handleUpdateAll('cancelled')}
            className="btn-annule-all"
            disabled={stats.pending === 0}
          >
            ❌ Annuler Tout ({stats.pending})
          </button>
        </div>
        
        {/* قائمة الطلبات التفصيلية */}
        <div className="group-orders-list">
          <h3 className="orders-list-title">
            🍽️ تفاصيل الطلبات ({localOrders.length})
          </h3>
          {localOrders.map((order, idx) => (
            <div 
              key={order.id} 
              className={`detail-order-item ${order.status} animate-slide-up`}
              style={{ animationDelay: `${idx * 0.05}s` }}
            >
              <div className="detail-order-number">#{order.id.slice(-4)}</div>
              <div className="detail-order-info">
                <div className="detail-order-time">🕐 {order.time || '--:--'}</div>
                <div className="detail-order-notes">
                  {order.notes ? `📝 ${order.notes}` : 'لا توجد ملاحظات'}
                </div>
              </div>
              <div className="detail-order-buttons">
                <button 
                  onClick={() => handleUpdateOrder(order.id, 'completed')}
                  className={`detail-btn-livre ${order.status === 'completed' ? 'active' : ''}`}
                  disabled={order.status !== 'pending'}
                >
                  ✅
                </button>
                <button 
                  onClick={() => handleUpdateOrder(order.id, 'cancelled')}
                  className={`detail-btn-annule ${order.status === 'cancelled' ? 'active' : ''}`}
                  disabled={order.status !== 'pending'}
                >
                  ❌
                </button>
              </div>
              <div className="detail-order-status">
                {order.status === 'pending' && <span className="status-pending">⏳</span>}
                {order.status === 'completed' && <span className="status-completed">✅</span>}
                {order.status === 'cancelled' && <span className="status-cancelled">❌</span>}
              </div>
            </div>
          ))}
        </div>
        
        {/* زر إغلاق في الأسفل */}
        <button onClick={onClose} className="btn-close-bottom">إغلاق</button>
      </div>
    </div>
  );
};

// ==================== مكون قائمة الطلبات الرئيسي ====================
const OrderList = ({ orders, onUpdateOrderStatus }) => {
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [showGroupDetails, setShowGroupDetails] = useState(false);
  const containerRef = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);

  // تجميع الطلبات المتطابقة (نفس المنتج)
  const groupOrders = () => {
    const groups = {};
    orders.forEach(order => {
      const key = `${order.name}_${order.price}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
      // تحديث الحالة العامة للمجموعة
      const hasPending = groups[key].orders.some(o => o.status === 'pending');
      const hasCompleted = groups[key].orders.some(o => o.status === 'completed');
      const hasCancelled = groups[key].orders.some(o => o.status === 'cancelled');
      
      if (hasPending) groups[key].status = 'pending';
      else if (hasCompleted && !hasCancelled) groups[key].status = 'completed';
      else if (hasCancelled && !hasCompleted) groups[key].status = 'cancelled';
      else if (hasCompleted && hasCancelled) groups[key].status = 'mixed';
    });
    return Object.values(groups);
  };

  const orderGroups = groupOrders();

  // التمرير التلقائي للأسفل عند إضافة طلب جديد
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [orders]);

  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // فتح تفاصيل المجموعة
  const openGroupDetails = (group) => {
    setSelectedGroup(group);
    setShowGroupDetails(true);
  };

  return (
    <>
      <div className="order-list-container">
        <div className="order-list-header">
          <h3 className="order-list-title">
            📋 قائمة الطلبات
            <span className="order-count-badge">{orders.length}</span>
          </h3>
          <div className="header-actions">
            <button className="refresh-btn" onClick={() => window.location.reload()}>
              🔄
            </button>
          </div>
        </div>
        
        <div 
          ref={containerRef}
          className="order-list-scroll"
          onScroll={handleScroll}
        >
          {orderGroups.length === 0 ? (
            <div className="empty-orders">
              <div className="empty-icon">🍽️</div>
              <p>لا توجد طلبات حالياً</p>
              <p className="empty-sub">ستظهر الطلبات هنا تلقائياً</p>
            </div>
          ) : (
            orderGroups.map((group, idx) => (
              <div 
                key={group.id}
                className={`order-group-item ${group.status} animate-slide-up`}
                style={{ animationDelay: `${idx * 0.05}s` }}
              >
                <div className="order-group-content">
                  <div className="order-info">
                    <span className="order-icon">
                      {group.name.includes('قهوة') ? '☕' : 
                       group.name.includes('شاي') ? '🍵' :
                       group.name.includes('بيتزا') ? '🍕' :
                       group.name.includes('برغر') ? '🍔' : '🍽️'}
                    </span>
                    <div className="order-details">
                      <div className="order-name">{group.name}</div>
                      <div className="order-meta">
                        <span className="order-price">{group.price} دج</span>
                        <span className="order-quantity-badge">×{group.quantity}</span>
                      </div>
                    </div>
                  </div>
                  <div className="order-group-actions">
                    <div className={`group-status ${group.status}`}>
                      {group.status === 'pending' && '⏳ انتظار'}
                      {group.status === 'completed' && '✅ مكتمل'}
                      {group.status === 'cancelled' && '❌ ملغي'}
                      {group.status === 'mixed' && '🔄 متنوع'}
                    </div>
                    <button 
                      className="btn-details"
                      onClick={() => openGroupDetails(group)}
                    >
                      📋 تفصيل
                    </button>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
        
        {showScrollButton && (
          <button className="scroll-to-top" onClick={scrollToTop}>
            ↑
          </button>
        )}
      </div>
      
      {/* مودال تفاصيل المجموعة */}
      {showGroupDetails && selectedGroup && (
        <GroupDetailsModal 
          group={selectedGroup}
          onUpdateOrderStatus={onUpdateOrderStatus}
          onClose={() => setShowGroupDetails(false)}
        />
      )}
    </>
  );
};

// ==================== المكون الرئيسي (نفسه لكن مع بيانات أكثر) ====================
export default function Profileemploye() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [showAddComment, setShowAddComment] = useState(false);
  const [showCommentsList, setShowCommentsList] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  
  // ========== حالة الطلبات مع تفاصيل أكثر ==========
  const [orders, setOrders] = useState([
    { id: 1001, name: "قهوة عربية", price: 150, status: "pending", time: "14:30", notes: "سكر أقل" },
    { id: 1002, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:32", notes: "" },
    { id: 1003, name: "قهوة عربية", price: 150, status: "pending", time: "14:35", notes: "بدون سكر" },
    { id: 1004, name: "كابتشينو", price: 250, status: "pending", time: "14:38", notes: "حليب ساخن" },
    { id: 1005, name: "قهوة عربية", price: 150, status: "pending", time: "14:40", notes: "" },
    { id: 1006, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:42", notes: "نعناع طازج" },
    { id: 1007, name: "لاتيه", price: 220, status: "pending", time: "14:45", notes: "حليب لوز" },
    { id: 1008, name: "قهوة عربية", price: 150, status: "pending", time: "14:48", notes: "سكر زيادة" },
  ]);
  
  // سجل التغييرات المؤقتة (لن يتم حفظها نهائياً حتى تأكيد لاحق)
  const [tempChanges, setTempChanges] = useState([]);
  
  const [comments, setComments] = useState([
    { id: 1, author: "Sophie Martin", text: "Excellente prestation !", rating: 5, date: "2024-03-15" },
    { id: 2, author: "Thomas Dubois", text: "Service rapide et professionnel.", rating: 4, date: "2024-03-10" },
  ]);
  
  const [newComment, setNewComment] = useState({ author: "", text: "", rating: 5 });
  
  const [workerInfo, setWorkerInfo] = useState({
    name: "Jenna Stones",
    role: "Serveuse / Barmaid",
    experience: "5 ans d'expérience",
    skills: ["Service client", "Gestion des commandes", "Polyvalence", "Travail d'équipe", "Anglais courant"],
    bio: "Serveuse professionnelle avec 5 ans d'expérience dans la restauration.",
    email: "jenna.stones@example.com",
    phone: "+33 6 12 34 56 78",
    location: "Paris, France",
  });
  
  const [workHistory, setWorkHistory] = useState([
    { place: "Le Café Paris", role: "Serveuse", duration: "2023 - Présent", rating: 5, review: "Excellente serveuse !" },
  ]);
  
  const [currentRating, setCurrentRating] = useState(0);
  const [managerComment, setManagerComment] = useState("");
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [showPlaceSelector, setShowPlaceSelector] = useState(false);
  
  // محاكاة وصول طلبات جديدة
  useEffect(() => {
    const interval = setInterval(() => {
      const names = ["قهوة عربية", "شاي بالنعناع", "كابتشينو", "لاتيه", "عصير برتقال"];
      const prices = [150, 120, 250, 220, 180];
      const randomIndex = Math.floor(Math.random() * names.length);
      
      const newOrder = {
        id: Date.now(),
        name: names[randomIndex],
        price: prices[randomIndex],
        status: "pending",
        time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
        notes: Math.random() > 0.8 ? "ملاحظة خاصة" : ""
      };
      
      setOrders(prev => [...prev, newOrder]);
    }, 30000); // كل 30 ثانية
    
    return () => clearInterval(interval);
  }, []);
  
  // تحديث حالة الطلبية (تسجيل مؤقت)
  const updateOrderStatus = (orderId, newStatus) => {
    // تسجيل التغيير في السجل المؤقت
    const change = {
      orderId,
      newStatus,
      timestamp: new Date().toISOString(),
      order: orders.find(o => o.id === orderId)
    };
    setTempChanges(prev => [...prev, change]);
    
    // تحديث الواجهة
    setOrders(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus, updated: true } : order
    ));
    
    console.log(`📝 تغيير مؤقت: الطلب #${orderId} -> ${newStatus}`);
  };
  
  const addComment = () => {
    if (newComment.author && newComment.text) {
      const comment = {
        id: comments.length + 1,
        author: newComment.author,
        text: newComment.text,
        rating: newComment.rating,
        date: new Date().toLocaleDateString('fr-FR')
      };
      setComments([comment, ...comments]);
      setNewComment({ author: "", text: "", rating: 5 });
      setShowAddComment(false);
      alert("✅ Merci pour votre commentaire !");
    }
  };
  
  const addManagerReview = () => {
    if (currentRating > 0 && managerComment) {
      const newHistory = {
        place: currentWorkPlace,
        role: workerInfo.role,
        duration: new Date().toLocaleDateString('fr-FR'),
        rating: currentRating,
        review: managerComment
      };
      setWorkHistory([newHistory, ...workHistory]);
      setCurrentRating(0);
      setManagerComment("");
      alert("✅ Évaluation ajoutée !");
    }
  };
  
  const changeWorkPlace = (place) => {
    setCurrentWorkPlace(place.name);
    setSelectedPlace(place);
    setShowPlaceSelector(false);
    setWorkerStatus("working");
    alert(`✅ Lieu changé : ${place.name}`);
  };
  
  const deactivateWorker = () => {
    setWorkerStatus("free");
    setCurrentWorkPlace("");
    alert("⚠️ Statut: En recherche");
  };
  
  const availablePlaces = [
    { id: 1, name: "Le Café Paris", location: "Paris", icon: "☕" },
    { id: 2, name: "Restaurant La Mer", location: "Marseille", icon: "🍽️" },
    { id: 3, name: "Tech Hub Lyon", location: "Lyon", icon: "💻" },
  ];

  // ==================== ستايل CSS كامل ====================
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      100% { background-position: 100% 50%; }
    }
    
    @keyframes slideUp {
      from { opacity: 0; transform: translateY(30px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .profile-hero-section {
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a);
      min-height: 100vh;
      padding-top: 80px;
    }
    
    /* ===== ستايل قائمة الطلبات ===== */
    .order-list-container {
      position: fixed;
      bottom: 20px;
      right: 20px;
      width: 400px;
      max-width: calc(100% - 40px);
      background: rgba(0, 0, 0, 0.9);
      backdrop-filter: blur(20px);
      border-radius: 20px;
      border: 1px solid rgba(34, 197, 94, 0.3);
      box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
      z-index: 100;
    }
    
    .order-list-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 15px 20px;
      background: linear-gradient(135deg, rgba(34, 197, 94, 0.2), transparent);
      border-radius: 20px 20px 0 0;
      border-bottom: 1px solid rgba(34, 197, 94, 0.3);
    }
    
    .order-list-title {
      color: white;
      font-size: 1.1rem;
      font-weight: bold;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    
    .order-count-badge {
      background: #22c55e;
      color: white;
      border-radius: 20px;
      padding: 2px 8px;
      font-size: 0.75rem;
    }
    
    .refresh-btn {
      background: rgba(255,255,255,0.1);
      border: none;
      color: white;
      cursor: pointer;
      padding: 5px 8px;
      border-radius: 8px;
    }
    
    .order-list-scroll {
      max-height: 450px;
      overflow-y: auto;
      padding: 10px;
    }
    
    .order-list-scroll::-webkit-scrollbar {
      width: 5px;
    }
    
    .order-list-scroll::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    
    .order-list-scroll::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    /* مجموعة الطلبات */
    .order-group-item {
      background: rgba(255, 255, 255, 0.1);
      border-radius: 12px;
      margin-bottom: 10px;
      border-left: 3px solid #22c55e;
      animation: slideUp 0.3s ease-out forwards;
      opacity: 0;
    }
    
    .order-group-item.pending { border-left-color: #f59e0b; }
    .order-group-item.completed { border-left-color: #22c55e; opacity: 0.7; }
    .order-group-item.cancelled { border-left-color: #ef4444; opacity: 0.7; }
    .order-group-item.mixed { border-left-color: #8b5cf6; }
    
    .order-group-content {
      padding: 12px 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .order-info {
      display: flex;
      align-items: center;
      gap: 12px;
      flex: 1;
    }
    
    .order-icon { font-size: 1.8rem; }
    
    .order-name {
      color: white;
      font-weight: 600;
      font-size: 0.95rem;
    }
    
    .order-meta {
      display: flex;
      gap: 10px;
      margin-top: 4px;
    }
    
    .order-price { color: #22c55e; font-size: 0.8rem; font-weight: bold; }
    .order-quantity-badge {
      background: rgba(34, 197, 94, 0.2);
      color: #22c55e;
      padding: 0px 6px;
      border-radius: 10px;
      font-size: 0.7rem;
    }
    
    .order-group-actions {
      display: flex;
      align-items: center;
      gap: 10px;
    }
    
    .group-status {
      font-size: 0.7rem;
      padding: 3px 8px;
      border-radius: 12px;
      background: rgba(0,0,0,0.5);
    }
    
    .group-status.pending { color: #f59e0b; }
    .group-status.completed { color: #22c55e; }
    .group-status.cancelled { color: #ef4444; }
    .group-status.mixed { color: #8b5cf6; }
    
    .btn-details {
      background: linear-gradient(135deg, #3b82f6, #1d4ed8);
      border: none;
      padding: 6px 12px;
      border-radius: 20px;
      color: white;
      font-size: 0.75rem;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-details:hover {
      transform: scale(1.05);
      box-shadow: 0 2px 8px rgba(59,130,246,0.4);
    }
    
    .scroll-to-top {
      position: absolute;
      bottom: 10px;
      right: 10px;
      background: #22c55e;
      border: none;
      color: white;
      width: 35px;
      height: 35px;
      border-radius: 50%;
      cursor: pointer;
    }
    
    /* مودال تفاصيل المجموعة */
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.85);
      backdrop-filter: blur(10px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    .modal-content-group {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 25px;
      max-width: 500px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #3b82f6;
      box-shadow: 0 0 40px rgba(59,130,246,0.3);
    }
    
    .modal-content-group::-webkit-scrollbar { width: 5px; }
    .modal-content-group::-webkit-scrollbar-thumb { background: #3b82f6; border-radius: 10px; }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
    }
    
    .group-details-header {
      text-align: center;
      margin-bottom: 20px;
    }
    
    .group-icon { font-size: 3rem; }
    .group-title { color: white; font-size: 1.5rem; margin: 10px 0 5px; }
    .group-subtitle { color: #22c55e; font-size: 0.9rem; }
    
    /* إحصائيات */
    .stats-row {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin-bottom: 20px;
    }
    
    .stat-card {
      flex: 1;
      text-align: center;
      padding: 10px;
      border-radius: 12px;
      background: rgba(255,255,255,0.1);
    }
    
    .stat-card.pending { border-bottom: 3px solid #f59e0b; }
    .stat-card.completed { border-bottom: 3px solid #22c55e; }
    .stat-card.cancelled { border-bottom: 3px solid #ef4444; }
    
    .stat-number { display: block; font-size: 1.5rem; font-weight: bold; color: white; }
    .stat-label { font-size: 0.7rem; color: rgba(255,255,255,0.6); }
    
    /* أزرار شاملة */
    .group-actions-all {
      display: flex;
      gap: 10px;
      margin-bottom: 20px;
    }
    
    .btn-livre-all, .btn-annule-all {
      flex: 1;
      padding: 10px;
      border: none;
      border-radius: 12px;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-livre-all {
      background: linear-gradient(135deg, #22c55e, #15803d);
      color: white;
    }
    
    .btn-annule-all {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      color: white;
    }
    
    .btn-livre-all:disabled, .btn-annule-all:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    
    /* قائمة الطلبات التفصيلية */
    .group-orders-list {
      max-height: 350px;
      overflow-y: auto;
      margin-bottom: 15px;
    }
    
    .orders-list-title {
      color: white;
      font-size: 0.9rem;
      margin-bottom: 10px;
      padding-bottom: 5px;
      border-bottom: 1px solid rgba(255,255,255,0.2);
    }
    
    .detail-order-item {
      display: flex;
      align-items: center;
      justify-content: space-between;
      background: rgba(255,255,255,0.08);
      border-radius: 10px;
      padding: 10px;
      margin-bottom: 8px;
      animation: slideUp 0.2s ease-out forwards;
      opacity: 0;
    }
    
    .detail-order-item.completed { opacity: 0.6; background: rgba(34,197,94,0.1); }
    .detail-order-item.cancelled { opacity: 0.6; background: rgba(239,68,68,0.1); }
    
    .detail-order-number {
      font-size: 0.7rem;
      color: #3b82f6;
      font-family: monospace;
      min-width: 50px;
    }
    
    .detail-order-info {
      flex: 1;
      margin: 0 10px;
    }
    
    .detail-order-time { font-size: 0.7rem; color: rgba(255,255,255,0.5); }
    .detail-order-notes { font-size: 0.7rem; color: #f59e0b; }
    
    .detail-order-buttons {
      display: flex;
      gap: 8px;
    }
    
    .detail-btn-livre, .detail-btn-annule {
      width: 32px;
      height: 32px;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-size: 1rem;
      transition: all 0.2s;
    }
    
    .detail-btn-livre {
      background: rgba(34,197,94,0.2);
      color: #22c55e;
    }
    
    .detail-btn-livre:hover:not(:disabled) {
      background: #22c55e;
      color: white;
      transform: scale(1.05);
    }
    
    .detail-btn-annule {
      background: rgba(239,68,68,0.2);
      color: #ef4444;
    }
    
    .detail-btn-annule:hover:not(:disabled) {
      background: #ef4444;
      color: white;
      transform: scale(1.05);
    }
    
    .detail-btn-livre.active, .detail-btn-annule.active {
      opacity: 0.5;
    }
    
    .detail-order-status { min-width: 30px; text-align: center; }
    .status-pending { color: #f59e0b; }
    .status-completed { color: #22c55e; }
    .status-cancelled { color: #ef4444; }
    
    .btn-close-bottom {
      width: 100%;
      padding: 10px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(255,255,255,0.2);
      border-radius: 12px;
      color: white;
      cursor: pointer;
      margin-top: 10px;
    }
    
    .empty-orders { text-align: center; padding: 40px; color: rgba(255,255,255,0.5); }
    .empty-icon { font-size: 3rem; margin-bottom: 10px; }
    
    /* باقي الستايلات */
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      margin-top: -60px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      background: linear-gradient(45deg, #ff0000, #fffb00, #48ff00, #00ffd5, #002bff);
      background-size: 450%;
      border-radius: 50%;
      animation: gradientShift 20s linear infinite;
      filter: blur(5px);
    }
    
    .cards-container {
      display: flex;
      gap: 20px;
      justify-content: center;
      margin-top: 40px;
      flex-wrap: wrap;
    }
    
    .cv-card {
      flex: 1;
      min-width: 260px;
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 35px 25px;
      cursor: pointer;
      text-align: center;
    }
    
    .cv-card:nth-child(1) { background: linear-gradient(135deg, #FF6B6B, #FF8E53); }
    .cv-card:nth-child(2) { background: linear-gradient(135deg, #4ECDC4, #556270); }
    .cv-card:nth-child(3) { background: linear-gradient(135deg, #A8E6CF, #3E92CC); }
    
    .btn-contact, .btn-comment {
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      border: none;
    }
    
    .btn-contact { background: linear-gradient(135deg, #22c55e, #15803d); }
    .btn-comment { background: linear-gradient(135deg, #ff6b6b, #f5576c); }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    
    .rating-star {
      font-size: 30px;
      cursor: pointer;
      color: #4a4a4a;
    }
    
    .rating-star.active { color: #ffc107; }
    
    .work-history-item {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
      border-left: 4px solid #22c55e;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      margin-left: 10px;
    }
    
    .status-working { background: #22c55e; color: white; }
    .status-free { background: #ef4444; color: white; }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      border: none;
      cursor: pointer;
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      border: none;
      cursor: pointer;
    }
    
    .comment-card {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
    }
    
    .profile-glow {
      position: absolute;
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3), transparent);
      border-radius: 50%;
      animation: fadeIn 2s infinite;
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
    }
    
    @media (max-width: 768px) {
      .order-list-container { width: calc(100% - 20px); right: 10px; bottom: 10px; }
      .cards-container { flex-direction: column; }
      .stats-row { flex-direction: row; flex-wrap: wrap; }
      .detail-order-item { flex-wrap: wrap; gap: 8px; }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="profile-hero-section">
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px" }}>
            <div className="hero-image" style={{ 
              backgroundImage: "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')",
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%',
              position: 'absolute',
              top: 0,
              width: '100%',
              height: '100%'
            }}></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 flex justify-center">
                      <div className="profile-image-wrapper">
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt="Profile" 
                            src="https://randomuser.me/api/portraits/women/68.jpg"
                            className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold text-white">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-green-400 mt-2">📍 {currentWorkPlace}</p>
                    )}
                    <div className="text-gray-300 mt-10">{workerInfo.role}</div>
                  </div>
                  
                  <div className="action-buttons" style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginTop: '20px' }}>
                    <button className="btn-contact" onClick={() => alert("📧 Email: jenna@example.com")}>
                      📧 Contacter
                    </button>
                    <button className="btn-comment" onClick={() => setShowCommentsList(true)}>
                      💬 Commenter
                    </button>
                  </div>
                  
                  <div className="cards-container">
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-6xl mb-4">📄</div>
                      <h3 className="text-xl font-bold text-white">Mon CV</h3>
                    </div>
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-6xl mb-4">⭐</div>
                      <h3 className="text-xl font-bold text-white">Évaluations</h3>
                    </div>
                    <div className="cv-card">
                      <div className="text-6xl mb-4">🚀</div>
                      <h3 className="text-xl font-bold text-white">Projets</h3>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <p className="text-gray-200 italic">"{workerInfo.bio}"</p>
                    <div className="flex justify-center gap-2 mt-4 flex-wrap">
                      {workerInfo.skills.map((skill, i) => (
                        <span key={i} className="skill-tag">{skill}</span>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* قائمة الطلبات */}
      <OrderList orders={orders} onUpdateOrderStatus={updateOrderStatus} />
      
      {/* باقي المودالات */}
      {showCommentsList && (
        <div className="modal-overlay" onClick={() => setShowCommentsList(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowCommentsList(false)} className="close-btn">✕</button>
            <div className="text-center">
              <h2 className="text-2xl font-bold text-white">Commentaires</h2>
              <button onClick={() => setShowAddComment(true)} className="btn-primary w-full my-4">
                ✏️ Écrire
              </button>
              {comments.map((comment) => (
                <div key={comment.id} className="comment-card">
                  <h4 className="text-white font-bold">{comment.author}</h4>
                  <p className="text-gray-300 text-sm">{comment.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      {showAddComment && (
        <div className="modal-overlay" onClick={() => setShowAddComment(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowAddComment(false)} className="close-btn">✕</button>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white mb-3" 
              placeholder="Votre nom" value={newComment.author} 
              onChange={(e) => setNewComment({...newComment, author: e.target.value})} />
            <textarea className="w-full p-3 rounded-xl bg-white/10 text-white" rows="4"
              placeholder="Votre commentaire" value={newComment.text}
              onChange={(e) => setNewComment({...newComment, text: e.target.value})} />
            <button onClick={addComment} className="btn-primary w-full mt-4">Publier</button>
          </div>
        </div>
      )}
      
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)} className="close-btn">✕</button>
            <h2 className="text-2xl font-bold text-white">{workerInfo.name}</h2>
            <p className="text-gray-300">{workerInfo.bio}</p>
          </div>
        </div>
      )}
      
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowManagerCV(false)} className="close-btn">✕</button>
            <h2 className="text-2xl font-bold text-white">Évaluations</h2>
            {workHistory.map((work, i) => (
              <div key={i} className="work-history-item">
                <h4 className="text-white">{work.place}</h4>
                <p className="text-gray-400">"{work.review}"</p>
              </div>
            ))}
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
